#include<bits/stdc++.h>
using namespace std;
int maxx=-1e9;
bool f(int n){
    if(n==0||n==1) return 0;
    for(int i=2;i*i<=n;i++) if(n%i==0) return false;
    return true;
}
int main(){
    int n;
    cin>>n;
     for(int i=2;i<=n;i++) if(f(i)) if(f(n-i)) maxx=max(maxx,i*(n-i));  
    cout<<maxx;
    return 0;
}
